PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE users (
	id INTEGER NOT NULL, 
	email VARCHAR, 
	full_name VARCHAR, 
	profile_picture_url VARCHAR, 
	role VARCHAR, 
	plan_tier VARCHAR, 
	initials VARCHAR, 
	personalization_nickname VARCHAR, 
	personalization_occupation VARCHAR, 
	personalization_about VARCHAR, 
	personalization_custom_instructions VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, auth_user_id TEXT, has_seen_general_chat BOOLEAN DEFAULT 0, maps_enabled BOOLEAN DEFAULT 0, daily_token_usage INTEGER DEFAULT 0, monthly_cost_usage REAL DEFAULT 0, weekly_cost_usage REAL DEFAULT 0, six_hour_cost_usage REAL DEFAULT 0, last_daily_reset TEXT, last_monthly_reset TEXT, last_weekly_reset TEXT, last_six_hour_reset TEXT, workspace_background_id TEXT, personalization_show_calendar BOOLEAN DEFAULT 1, daily_gemini_pro_usage INTEGER DEFAULT 0, last_daily_gemini_pro_reset TEXT, personalization_system_prompt_override TEXT, preferred_model TEXT, subscription_expires_at DATETIME, "improve_model_for_everyone" BOOLEAN DEFAULT 0, 
	PRIMARY KEY (id)
);
CREATE TABLE workspace_backgrounds (
	id INTEGER NOT NULL, 
	slug VARCHAR, 
	label VARCHAR NOT NULL, 
	description VARCHAR, 
	preview_css TEXT NOT NULL, 
	backdrop_css TEXT NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE user_data (
	id INTEGER NOT NULL, 
	user_identifier INTEGER NOT NULL, 
	nickname VARCHAR, 
	occupation VARCHAR, 
	about VARCHAR, 
	custom_instructions VARCHAR, 
	has_seen_general_chat BOOLEAN, 
	created_at DATETIME, 
	updated_at DATETIME, profile JSON, context JSON, metadata JSON, workspace_context TEXT, long_term_memory TEXT, 
	PRIMARY KEY (id), 
	UNIQUE (user_identifier)
);
CREATE TABLE transactions (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	order_id VARCHAR NOT NULL, 
	amount INTEGER NOT NULL, 
	status VARCHAR, 
	payment_type VARCHAR, 
	plan_tier VARCHAR NOT NULL, 
	snap_token VARCHAR, 
	snap_redirect_url VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, billing_cycle VARCHAR, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE chat_sessions (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	title VARCHAR, 
	scope VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE calendars (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	label VARCHAR, 
	color VARCHAR, 
	is_visible BOOLEAN, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE plans (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	label VARCHAR, 
	completed BOOLEAN, 
	deadline VARCHAR, 
	schedule_slot VARCHAR, 
	description VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE proactive_state (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	next_check_at DATETIME, 
	queued_signature VARCHAR, 
	queued_reason VARCHAR, 
	queued_window VARCHAR, 
	queued_time_label VARCHAR, 
	engagement_snapshot JSON, 
	window_preferences JSON, 
	metadata JSON, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE habits (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	label VARCHAR, 
	streak_label VARCHAR, 
	previous_label VARCHAR, 
	description VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE reminders (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	entity_type VARCHAR, 
	entity_id INTEGER, 
	delivery_mode VARCHAR, 
	label VARCHAR NOT NULL, 
	description VARCHAR, 
	summary VARCHAR, 
	remind_at DATETIME NOT NULL, 
	status VARCHAR, 
	metadata JSON, 
	created_at DATETIME, 
	updated_at DATETIME, 
	delivered_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE dashboard_pulses (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	date_key VARCHAR NOT NULL, 
	timestamp DATETIME NOT NULL, 
	plans JSON NOT NULL, 
	habits JSON NOT NULL, 
	proactivity JSON NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_dashboard_pulses_user_date UNIQUE (user_id, date_key), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE proactivity_settings (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	payload JSON NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE proactivity_push_subscriptions (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	endpoint VARCHAR NOT NULL, 
	p256dh VARCHAR NOT NULL, 
	auth VARCHAR NOT NULL, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	UNIQUE (endpoint)
);
CREATE TABLE user_streaks (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	current_streak INTEGER, 
	last_activity_date DATETIME, 
	created_at DATETIME, 
	updated_at DATETIME, longest_streak INTEGER DEFAULT 0, 
	PRIMARY KEY (id), 
	UNIQUE (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE proactivity_logs (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	activity_date DATETIME, 
	tasks_completed INTEGER, 
	total_tasks INTEGER, 
	score INTEGER, 
	notes VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE context_cache (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	conversation_id VARCHAR, 
	label VARCHAR, 
	content TEXT NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE proactive_notifications (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	type VARCHAR, 
	title VARCHAR, 
	message VARCHAR, 
	metadata JSON, 
	due_at DATETIME, 
	sent_at DATETIME, 
	read_at DATETIME, 
	completed_at DATETIME, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE file_search_stores (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	store_name VARCHAR, 
	display_name VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (user_id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	UNIQUE (store_name)
);
CREATE TABLE media_uploads (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	filename VARCHAR, 
	mime_type VARCHAR, 
	size INTEGER, 
	storage_path VARCHAR, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE google_calendar_credentials (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	access_token VARCHAR, 
	refresh_token VARCHAR, 
	token_uri VARCHAR, 
	client_id VARCHAR, 
	client_secret VARCHAR, 
	scopes VARCHAR, 
	expires_at DATETIME, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE google_calendar_states (
	id INTEGER NOT NULL, 
	state_token VARCHAR NOT NULL, 
	user_id INTEGER, 
	nonce VARCHAR NOT NULL, 
	redirect_uri VARCHAR NOT NULL, 
	expires_at DATETIME, 
	consumed_at DATETIME, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	UNIQUE (state_token), 
	FOREIGN KEY(user_id) REFERENCES users (id)
);
CREATE TABLE general_chat_messages (
	id INTEGER NOT NULL, 
	user_id INTEGER NOT NULL, 
	user_data_id INTEGER NOT NULL, 
	role VARCHAR NOT NULL, 
	content TEXT NOT NULL, 
	grounding_metadata JSON, 
	attachments JSON, 
	created_at DATETIME, reminders JSON DEFAULT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_data_id) REFERENCES user_data (id)
);
CREATE TABLE calendar_events (
	id INTEGER NOT NULL, 
	user_id INTEGER, 
	calendar_id INTEGER, 
	title VARCHAR, 
	description VARCHAR, 
	start_time DATETIME, 
	end_time DATETIME, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(user_id) REFERENCES users (id), 
	FOREIGN KEY(calendar_id) REFERENCES calendars (id)
);
CREATE TABLE user_chat_threads (
    id TEXT PRIMARY KEY,
    user_data_id INTEGER NOT NULL,
    user_identifier INTEGER NOT NULL,
    title TEXT DEFAULT 'New Conversation',
    summary TEXT,
    context_snapshot TEXT DEFAULT '[]',
    metadata TEXT DEFAULT '{}',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    last_message_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_data_id) REFERENCES user_data(id)
);
CREATE TABLE user_chat_messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    thread_id TEXT NOT NULL,
    role TEXT NOT NULL,
    text TEXT NOT NULL,
    grounding_metadata TEXT,
    attachments TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, reminders JSON DEFAULT NULL,
    FOREIGN KEY (thread_id) REFERENCES user_chat_threads(id)
);
CREATE TABLE archived_chat_messages (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        user_data_id INTEGER,
        role TEXT NOT NULL,
        content TEXT NOT NULL,
        grounding_metadata JSON,
        attachments JSON,
        reminders JSON,
        original_created_at DATETIME,
        archived_at DATETIME DEFAULT CURRENT_TIMESTAMP,
        compression_batch_id TEXT,
        FOREIGN KEY(user_id) REFERENCES users(id)
    );
DELETE FROM sqlite_sequence;
CREATE INDEX ix_users_id ON users (id);
CREATE UNIQUE INDEX ix_users_email ON users (email);
CREATE UNIQUE INDEX ix_workspace_backgrounds_slug ON workspace_backgrounds (slug);
CREATE INDEX ix_workspace_backgrounds_id ON workspace_backgrounds (id);
CREATE INDEX ix_user_data_id ON user_data (id);
CREATE INDEX ix_transactions_id ON transactions (id);
CREATE UNIQUE INDEX ix_transactions_order_id ON transactions (order_id);
CREATE INDEX ix_chat_sessions_id ON chat_sessions (id);
CREATE INDEX ix_calendars_id ON calendars (id);
CREATE INDEX ix_plans_id ON plans (id);
CREATE INDEX ix_proactive_state_id ON proactive_state (id);
CREATE INDEX ix_habits_id ON habits (id);
CREATE INDEX ix_reminders_id ON reminders (id);
CREATE INDEX ix_dashboard_pulses_id ON dashboard_pulses (id);
CREATE INDEX ix_proactivity_settings_id ON proactivity_settings (id);
CREATE INDEX ix_proactivity_push_subscriptions_id ON proactivity_push_subscriptions (id);
CREATE INDEX ix_user_streaks_id ON user_streaks (id);
CREATE INDEX ix_proactivity_logs_id ON proactivity_logs (id);
CREATE INDEX ix_context_cache_id ON context_cache (id);
CREATE INDEX ix_proactive_notifications_id ON proactive_notifications (id);
CREATE INDEX ix_file_search_stores_id ON file_search_stores (id);
CREATE INDEX ix_media_uploads_id ON media_uploads (id);
CREATE INDEX ix_google_calendar_credentials_id ON google_calendar_credentials (id);
CREATE INDEX ix_google_calendar_states_id ON google_calendar_states (id);
CREATE INDEX ix_general_chat_messages_id ON general_chat_messages (id);
CREATE INDEX ix_calendar_events_id ON calendar_events (id);
CREATE INDEX idx_user_chat_threads_user_identifier ON user_chat_threads(user_identifier);
CREATE INDEX idx_user_chat_messages_thread_id ON user_chat_messages(thread_id);
CREATE INDEX ix_user_chat_messages_thread_id ON user_chat_messages (thread_id);
CREATE INDEX ix_archived_chat_messages_user_id ON archived_chat_messages (user_id);
COMMIT;
