INSERT INTO user_chat_messages VALUES(21,'ea4b548d-7899-45fe-91a7-bda865cc5ac2','model',replace('Grady, why did the AI go to art school?  \n\nIt wanted to learn how to draw better *conclusions*! 😎  \n\nWant another?','\n',char(10)),'null','null','2025-12-05 11:17:22.048760',NULL);
INSERT INTO user_chat_messages VALUES(22,'43a35d64-f178-4fa9-ade7-0135f7cff2ff','user','tell a joke','null','null','2025-12-05 11:17:22.576305',NULL);
INSERT INTO user_chat_messages VALUES(23,'43a35d64-f178-4fa9-ade7-0135f7cff2ff','model',replace('A joke, coming right up, Grady. Given your CEO and Alignment status, I''ll aim for something with a bit of bite.\n\nWhy don''t you ever see a CEO using a napkin?\n\n...Because they prefer to wipe their mouth with the **bottom line**.\n\nSharp enough for you? Now, on to business. Anything I can proactively handle for you right now—a reminder for a crucial deadline, or perhaps a quick status check on your open research plans?','\n',char(10)),'null','null','2025-12-05 11:17:29.238762',NULL);
INSERT INTO user_chat_messages VALUES(24,'5ebc6fff-34cf-4c52-bae4-070855ef1ab5','user','tell a joke','null','null','2025-12-05 12:14:36.750323',NULL);
INSERT INTO user_chat_messages VALUES(25,'5ebc6fff-34cf-4c52-bae4-070855ef1ab5','model',replace('Hey Grady, why did the AI researcher refuse to play cards with the neural network?  \n\nIt kept trying to backpropagate the blame! 😆  \n\nWant another, or something more alignment-flavored?','\n',char(10)),'null','null','2025-12-05 12:14:43.132805',NULL);
