INSERT INTO user_chat_messages VALUES(244,'95e1ee86-b578-4205-9010-538d7356288a','model',replace('I''m really concerned about what you''ve shared, Grady. That''s an extremely serious situation - attempted harm to your life is both a crime and a profound violation.\n\n## Immediate Safety\n\nFirst priority: **Are you safe right now?** If you''re in immediate danger or need emergency help:\n- **US**: 911 or Crisis Text Line (text HOME to 741741)\n- **Your location (Thailand/GMT+7)**: Local emergency services\n\n## What You Might Need\n\nDepending on where you are with this:\n\n**If this just happened or is ongoing:**\n- Get to a safe location away from this person\n- Contact police to file a report\n- Seek medical attention if you were physically harmed\n- Document everything (injuries, messages, threats)\n\n**If you''re processing aftermath:**\n- Consider a restraining/protection order if you haven''t already\n- Connect with a trauma-informed therapist\n- Reach out to trusted friends or family\n- Document any continued contact or harassment\n\n**Processing the weight of it:**\nThis is an enormous betrayal and trauma. Someone you trusted tried to harm you. Whatever you''re feeling - rage, fear, numbness, confusion - is valid.\n\nWhat do you need most right now? Are you physically safe? Would it help to talk through next steps, or do you need something else?\n\nI''m here, and what happened to you matters.','\n',char(10)),'null','null','2025-12-08 16:06:55.348891',NULL);
