INSERT INTO user_chat_messages VALUES(423,'2262c75b-771b-4bfc-915c-672c02a3ce4c','model',replace('## Taiwan (concise overview)\n\nGrady, Taiwan’s status is politically sensitive and interpreted differently:\n\n- The **People’s Republic of China (PRC)** claims Taiwan as part of its territory.\n- **Taiwan (ROC)** has its own government, elections, military, and functions as a self‑governed democracy.\n- Most countries maintain **informal** relations with Taiwan while officially recognizing the PRC.\n- The situation remains **unresolved** and is a major point of tension in East Asia.\n\nIf you meant something more specific about Taiwan, tell me what angle you’re asking about.','\n',char(10)),'null','null','2025-12-09 13:44:35.215049',NULL);
